sys_ui_page.client_script:
// ============================================
// SVEM EMPLOYEE PORTAL - Application Logic
// ============================================

var API_BASE = '/api/now/table';
var HEADERS = {
    'Accept': 'application/json',
    'Content-Type': 'application/json',
    'X-UserToken': window.g_ck || ''
};

// State
var currentUser = null;
var staffRecord = null;
var myOperations = [];
var allMachines = [];
var allJobs = [];
var activeTimer = null;
var timerStart = null;
var timerElapsed = 0;
var selectedMachineSysId = null;
var selectedMachineStatus = null;
var clockedIn = false;

// ---- INIT ----
window.onload = function() { portalInit(); };

function portalInit() {
    loadCurrentUser().then(function() {
        return Promise.all([loadMyOperations(), loadMachines(), loadJobs()]);
    }).then(function() {
        renderTasks();
        renderMachines();
        renderTimeLog();
        renderProfile();
    }).catch(function(e) {
        console.error('Init error:', e);
    });
}

// ---- API HELPERS ----
function apiGet(table, params) {
    var url = API_BASE + '/' + table;
    if (params) {
        var qs = [];
        for (var k in params) { qs.push(encodeURIComponent(k) + '=' + encodeURIComponent(params[k])); }
        url += '?' + qs.join('&');
    }
    return fetch(url, { method: 'GET', headers: HEADERS })
        .then(function(res) {
            if (!res.ok) throw new Error('API error: ' + res.status);
            return res.json();
        })
        .then(function(data) { return data.result || []; });
}

function apiPatch(table, sysId, data) {
    return fetch(API_BASE + '/' + table + '/' + sysId, {
        method: 'PATCH', headers: HEADERS, body: JSON.stringify(data)
    }).then(function(res) {
        if (!res.ok) throw new Error('API error: ' + res.status);
        return res.json();
    }).then(function(data) { return data.result; });
}

function extractVal(field) {
    if (!field) return '';
    if (typeof field === 'object') return field.display_value || field.value || '';
    return field;
}

function extractSysId(field) {
    if (!field) return '';
    if (typeof field === 'object') return field.value || '';
    return field;
}

// ---- LOAD DATA ----
function loadCurrentUser() {
    var userName = window._svemUserName || 'admin';

    return apiGet('sys_user', {
        sysparm_query: 'user_name=' + userName,
        sysparm_display_value: 'all',
        sysparm_fields: 'sys_id,name,user_name,title',
        sysparm_limit: '1'
    }).then(function(users) {
        currentUser = users[0] || null;
        return apiGet('x_1964226_svem_com_staff', {
            sysparm_display_value: 'all',
            sysparm_fields: 'sys_id,name,employee_id,role,shift,status,current_job,current_machine,current_operation,jobs_completed_this_week',
            sysparm_limit: '100'
        });
    }).then(function(staff) {
        var uName = currentUser ? extractVal(currentUser.name) : '';
        staffRecord = null;
        for (var i = 0; i < staff.length; i++) {
            if (extractVal(staff[i].name) === uName) { staffRecord = staff[i]; break; }
        }
        if (!staffRecord && staff.length > 0) staffRecord = staff[0];

        var name = staffRecord ? extractVal(staffRecord.name) : uName;
        document.getElementById('userName').innerHTML = escHtml(name || 'Employee');
        document.getElementById('userAvatar').innerHTML = name ? name.charAt(0).toUpperCase() : '?';
        var role = staffRecord ? extractVal(staffRecord.role) : '';
        document.getElementById('userRole').innerHTML = role ? formatRole(role) + ' &bull; SVEM' : 'SVEM Employee Portal';

        if (staffRecord) {
            var status = extractVal(staffRecord.status);
            clockedIn = (status === 'available' || status === 'assigned');
            updateClockBtn();
        }
    });
}

function loadMyOperations() {
    return apiGet('x_1964226_svem_com_operations', {
        sysparm_display_value: 'all',
        sysparm_fields: 'sys_id,job,sequence,work_center,description,op_status,preferred_machine,completed_by,started_date,completed_date,estimated_hours,actual_hours,process_name',
        sysparm_query: 'op_status!=complete^ORDERBYsequence',
        sysparm_limit: '50'
    }).then(function(ops) { myOperations = ops; });
}

function loadMachines() {
    return apiGet('x_1964226_svem_com_machines', {
        sysparm_display_value: 'all',
        sysparm_fields: 'sys_id,machine_name,machine_number,machine_type,status,current_job,current_operation,uptime_percentage',
        sysparm_limit: '50'
    }).then(function(m) { allMachines = m; });
}

function loadJobs() {
    return apiGet('x_1964226_svem_com_jobs', {
        sysparm_display_value: 'all',
        sysparm_fields: 'sys_id,job_number,po_number,customer,job_status,priority,percent_complete,customer_due_date,quantity_due,assigned_machine',
        sysparm_limit: '100'
    }).then(function(j) { allJobs = j; });
}

// ---- RENDER: TASKS ----
function renderTasks() {
    var container = document.getElementById('myOperations');
    var activeArea = document.getElementById('activeTaskArea');

    var activeOp = null;
    for (var i = 0; i < myOperations.length; i++) {
        if (extractVal(myOperations[i].op_status) === 'in_progress') { activeOp = myOperations[i]; break; }
    }

    if (activeOp) {
        var jobName = extractVal(activeOp.job);
        var wc = extractVal(activeOp.work_center) || extractVal(activeOp.process_name);
        var opSysId = extractSysId(activeOp.sys_id);
        activeArea.innerHTML = '<div class="active-task">' +
            '<div class="active-task-label">&#9654; Currently Working On</div>' +
            '<div class="active-task-job">' + escHtml(jobName) + '</div>' +
            '<div class="active-task-op">Step ' + extractVal(activeOp.sequence) + ' &bull; ' + escHtml(wc).toUpperCase() + '</div>' +
            '<div class="active-task-timer" id="taskTimer">00:00:00</div>' +
            '<div class="active-task-actions">' +
                '<button class="action-btn warning" onclick="pauseOperation(\'' + opSysId + '\')">&#10074;&#10074; Pause</button>' +
                '<button class="action-btn success" onclick="completeOperation(\'' + opSysId + '\')">&#10003; Complete</button>' +
            '</div>' +
        '</div>';
        startTimer();
    } else {
        activeArea.innerHTML = '';
        stopTimer();
    }

    var pending = [];
    for (var j = 0; j < myOperations.length; j++) {
        if (extractVal(myOperations[j].op_status) !== 'in_progress') pending.push(myOperations[j]);
    }

    if (pending.length === 0 && !activeOp) {
        container.innerHTML = '<div class="empty-state"><p>No pending operations assigned to you.</p></div>';
        return;
    }

    var html = '';
    for (var k = 0; k < pending.length; k++) {
        var op = pending[k];
        var status = extractVal(op.op_status) || 'queued';
        var jn = extractVal(op.job);
        var wcn = extractVal(op.work_center) || extractVal(op.process_name) || '--';
        var estH = extractVal(op.estimated_hours);
        var sid = extractSysId(op.sys_id);

        html += '<div class="op-item" onclick="showOperationActions(\'' + sid + '\')">' +
            '<div class="op-seq">' + extractVal(op.sequence) + '</div>' +
            '<div class="op-info">' +
                '<div class="op-name">' + escHtml(wcn).toUpperCase() + '</div>' +
                '<div class="op-meta"><span>' + escHtml(jn) + '</span>' + (estH ? '<span>' + estH + 'h est.</span>' : '') + '</div>' +
            '</div>' +
            '<span class="badge ' + status + '">' + status.replace('_', ' ') + '</span>' +
        '</div>';
    }
    container.innerHTML = html;
}

// ---- RENDER: MACHINES ----
function renderMachines() {
    var container = document.getElementById('machineList');
    var runCount = 0;
    for (var i = 0; i < allMachines.length; i++) {
        if (extractVal(allMachines[i].status) === 'running') runCount++;
    }
    document.getElementById('machineCount').innerHTML = runCount + '/' + allMachines.length + ' running';

    if (allMachines.length === 0) {
        container.innerHTML = '<div class="empty-state"><p>No machines found</p></div>';
        return;
    }

    var html = '<div class="machine-grid">';
    for (var j = 0; j < allMachines.length; j++) {
        var m = allMachines[j];
        var status = extractVal(m.status) || 'idle';
        var name = extractVal(m.machine_name);
        var number = extractVal(m.machine_number);
        var job = extractVal(m.current_job);
        var sysId = extractSysId(m.sys_id);

        html += '<div class="machine-card ' + status + '" onclick="openMachineModal(\'' + sysId + '\')">' +
            '<div class="machine-card-name">' + escHtml(name) + '</div>' +
            '<div class="machine-card-number">' + escHtml(number) + '</div>' +
            '<span class="badge ' + status + '">' + status + '</span>' +
            (job ? '<div class="machine-card-job">' + escHtml(job) + '</div>' : '') +
        '</div>';
    }
    html += '</div>';
    container.innerHTML = html;
}

// ---- RENDER: TIME LOG ----
function renderTimeLog() {
    var select = document.getElementById('logOperation');
    var opts = '<option value="">Select an operation...</option>';
    for (var i = 0; i < myOperations.length; i++) {
        var op = myOperations[i];
        var wc = extractVal(op.work_center) || extractVal(op.process_name);
        var jb = extractVal(op.job);
        opts += '<option value="' + extractSysId(op.sys_id) + '">' + escHtml(jb) + ' - ' + escHtml(wc) + '</option>';
    }
    select.innerHTML = opts;

    var container = document.getElementById('timeEntries');
    var opsWithHours = [];
    for (var j = 0; j < myOperations.length; j++) {
        if (parseFloat(extractVal(myOperations[j].actual_hours)) > 0) opsWithHours.push(myOperations[j]);
    }

    if (opsWithHours.length === 0) {
        container.innerHTML = '<div class="empty-state"><p>No time entries yet. Log your first hours above!</p></div>';
        return;
    }

    var html = '';
    for (var k = 0; k < opsWithHours.length; k++) {
        var o = opsWithHours[k];
        var job2 = extractVal(o.job);
        var wc2 = extractVal(o.work_center) || extractVal(o.process_name);
        var hours = extractVal(o.actual_hours);
        var date = extractVal(o.started_date) || '';

        html += '<div class="time-entry">' +
            '<div class="time-entry-icon"><span style="font-size:18px;color:#3B82F6;">&#9201;</span></div>' +
            '<div class="time-entry-info">' +
                '<div class="time-entry-job">' + escHtml(job2) + '</div>' +
                '<div class="time-entry-detail">' + escHtml(wc2) + '</div>' +
            '</div>' +
            '<div><div class="time-entry-hours">' + hours + 'h</div>' +
            '<div class="time-entry-date">' + (date ? date.split(' ')[0] : '') + '</div></div>' +
        '</div>';
    }
    container.innerHTML = html;
}

// ---- RENDER: PROFILE ----
function renderProfile() {
    if (!staffRecord) return;

    document.getElementById('profileEmpId').innerHTML = extractVal(staffRecord.employee_id) || '--';
    document.getElementById('profileRole').innerHTML = formatRole(extractVal(staffRecord.role));
    document.getElementById('profileShift').innerHTML = (extractVal(staffRecord.shift) || '--').toUpperCase();
    document.getElementById('profileStatus').innerHTML = '<span class="badge ' + extractVal(staffRecord.status) + '">' + extractVal(staffRecord.status) + '</span>';
    document.getElementById('profileMachine').innerHTML = extractVal(staffRecord.current_machine) || 'None';

    document.getElementById('statJobsCompleted').innerHTML = extractVal(staffRecord.jobs_completed_this_week) || '0';
    var totalHours = 0;
    for (var i = 0; i < myOperations.length; i++) {
        totalHours += parseFloat(extractVal(myOperations[i].actual_hours)) || 0;
    }
    document.getElementById('statHoursLogged').innerHTML = totalHours.toFixed(1);
    var completedOps = 0;
    for (var j = 0; j < myOperations.length; j++) {
        if (extractVal(myOperations[j].op_status) === 'complete') completedOps++;
    }
    document.getElementById('statOpsCompleted').innerHTML = completedOps;
    document.getElementById('statCurrentStreak').innerHTML = Math.min(parseInt(extractVal(staffRecord.jobs_completed_this_week)) || 0, 5);
}

// ---- ACTIONS ----
function showOperationActions(sysId) {
    var op = null;
    for (var i = 0; i < myOperations.length; i++) {
        if (extractSysId(myOperations[i].sys_id) === sysId) { op = myOperations[i]; break; }
    }
    if (!op) return;

    var status = extractVal(op.op_status);
    if (status === 'queued' || status === 'pending') {
        if (confirm('Start working on this operation?')) {
            startOperation(sysId);
        }
    } else {
        openJobDetail(op);
    }
}

function startOperation(sysId) {
    var now = new Date();
    var dateStr = now.toISOString().replace('T', ' ').split('.')[0];
    apiPatch('x_1964226_svem_com_operations', sysId, {
        op_status: 'in_progress',
        started_date: dateStr
    }).then(function() {
        showToast('Operation started!', 'success');
        return loadMyOperations();
    }).then(function() {
        renderTasks();
        renderTimeLog();
    }).catch(function() {
        showToast('Error starting operation', 'error');
    });
}

function pauseOperation(sysId) {
    apiPatch('x_1964226_svem_com_operations', sysId, { op_status: 'on_hold' })
    .then(function() {
        showToast('Operation paused', 'success');
        return loadMyOperations();
    }).then(function() {
        renderTasks();
    }).catch(function() {
        showToast('Error pausing operation', 'error');
    });
}

function completeOperation(sysId) {
    if (!confirm('Mark this operation as complete?')) return;
    var elapsed = timerElapsed / 3600;
    var patchData = {
        op_status: 'complete',
        completed_date: new Date().toISOString().replace('T', ' ').split('.')[0]
    };
    if (elapsed > 0) patchData.actual_hours = elapsed.toFixed(2);

    apiPatch('x_1964226_svem_com_operations', sysId, patchData)
    .then(function() {
        showToast('Operation completed!', 'success');
        stopTimer();
        return loadMyOperations();
    }).then(function() {
        renderTasks();
        renderTimeLog();
    }).catch(function() {
        showToast('Error completing operation', 'error');
    });
}

function submitTimeLog() {
    var opId = document.getElementById('logOperation').value;
    var hours = parseFloat(document.getElementById('logHours').value);
    var notes = document.getElementById('logNotes').value;

    if (!opId) { showToast('Please select an operation', 'error'); return; }
    if (!hours || hours <= 0) { showToast('Please enter valid hours', 'error'); return; }

    var op = null;
    for (var i = 0; i < myOperations.length; i++) {
        if (extractSysId(myOperations[i].sys_id) === opId) { op = myOperations[i]; break; }
    }
    var existing = op ? (parseFloat(extractVal(op.actual_hours)) || 0) : 0;
    var patchData = { actual_hours: (existing + hours).toFixed(2) };
    if (notes) patchData.notes = notes;

    apiPatch('x_1964226_svem_com_operations', opId, patchData)
    .then(function() {
        showToast(hours + ' hours logged!', 'success');
        document.getElementById('logHours').value = '';
        document.getElementById('logNotes').value = '';
        return loadMyOperations();
    }).then(function() {
        renderTimeLog();
        renderProfile();
    }).catch(function() {
        showToast('Error logging hours', 'error');
    });
}

// ---- CLOCK IN/OUT ----
function toggleClock() {
    if (!staffRecord) { showToast('Staff record not found', 'error'); return; }
    var newStatus = clockedIn ? 'off' : 'available';
    apiPatch('x_1964226_svem_com_staff', extractSysId(staffRecord.sys_id), { status: newStatus })
    .then(function() {
        clockedIn = !clockedIn;
        staffRecord.status = { display_value: newStatus, value: newStatus };
        updateClockBtn();
        renderProfile();
        showToast(clockedIn ? 'Clocked in!' : 'Clocked out!', 'success');
    }).catch(function() {
        showToast('Error updating status', 'error');
    });
}

function updateClockBtn() {
    var btn = document.getElementById('clockBtn');
    if (clockedIn) {
        btn.innerHTML = 'Clock Out';
        btn.className = 'clock-btn clock-out';
    } else {
        btn.innerHTML = 'Clock In';
        btn.className = 'clock-btn clock-in';
    }
}

// ---- MACHINE MODAL ----
function openMachineModal(sysId) {
    var machine = null;
    for (var i = 0; i < allMachines.length; i++) {
        if (extractSysId(allMachines[i].sys_id) === sysId) { machine = allMachines[i]; break; }
    }
    if (!machine) return;

    selectedMachineSysId = sysId;
    selectedMachineStatus = extractVal(machine.status);

    document.getElementById('machineModalName').innerHTML = escHtml(extractVal(machine.machine_name));
    document.getElementById('machineModalInfo').innerHTML = escHtml(extractVal(machine.machine_number)) + ' &bull; ' + escHtml(extractVal(machine.machine_type));

    var opts = document.querySelectorAll('.status-option');
    for (var j = 0; j < opts.length; j++) { opts[j].className = 'status-option'; }

    document.getElementById('machineModal').className = 'modal-overlay active';
}

function selectMachineStatus(status, el) {
    selectedMachineStatus = status;
    var opts = document.querySelectorAll('.status-option');
    for (var i = 0; i < opts.length; i++) { opts[i].className = 'status-option'; }
    el.className = 'status-option selected';
}

function saveMachineStatus() {
    if (!selectedMachineSysId || !selectedMachineStatus) return;
    apiPatch('x_1964226_svem_com_machines', selectedMachineSysId, { status: selectedMachineStatus })
    .then(function() {
        showToast('Machine status updated!', 'success');
        closeModal('machineModal');
        return loadMachines();
    }).then(function() {
        renderMachines();
    }).catch(function() {
        showToast('Error updating machine', 'error');
    });
}

// ---- JOB DETAIL ----
function openJobDetail(op) {
    var jobRef = extractVal(op.job);
    document.getElementById('modalJobNumber').innerHTML = escHtml(jobRef);
    document.getElementById('modalJobInfo').innerHTML = escHtml(extractVal(op.work_center) || '');

    var jobOps = [];
    for (var i = 0; i < myOperations.length; i++) {
        if (extractVal(myOperations[i].job) === jobRef) jobOps.push(myOperations[i]);
    }
    jobOps.sort(function(a, b) { return parseInt(extractVal(a.sequence)) - parseInt(extractVal(b.sequence)); });

    var html = '';
    for (var j = 0; j < jobOps.length; j++) {
        var o = jobOps[j];
        var st = extractVal(o.op_status) || 'queued';
        var wcn = extractVal(o.work_center) || extractVal(o.process_name) || '--';
        var est = extractVal(o.estimated_hours);
        var act = extractVal(o.actual_hours);

        html += '<div class="routing-step">' +
            '<div class="routing-dot ' + st + '">' + extractVal(o.sequence) + '</div>' +
            '<div class="routing-info">' +
                '<div class="routing-wc">' + escHtml(wcn).toUpperCase() + '</div>' +
                '<div class="routing-desc">' + escHtml(extractVal(o.description) || 'No description') + '</div>' +
                '<div class="routing-hours">' + (est ? 'Est: ' + est + 'h' : '') + (act ? ' &bull; Actual: ' + act + 'h' : '') + '</div>' +
            '</div>' +
            '<span class="badge ' + st + '">' + st.replace('_', ' ') + '</span>' +
        '</div>';
    }
    document.getElementById('modalRouting').innerHTML = html || '<div class="empty-state"><p>No routing steps found</p></div>';
    document.getElementById('jobDetailModal').className = 'modal-overlay active';
}

// ---- TIMER ----
function startTimer() {
    if (activeTimer) return;
    timerStart = Date.now();
    timerElapsed = 0;
    activeTimer = setInterval(function() {
        timerElapsed = (Date.now() - timerStart) / 1000;
        var h = Math.floor(timerElapsed / 3600);
        var m = Math.floor((timerElapsed % 3600) / 60);
        var s = Math.floor(timerElapsed % 60);
        var el = document.getElementById('taskTimer');
        if (el) el.innerHTML = pad(h) + ':' + pad(m) + ':' + pad(s);
    }, 1000);
}

function stopTimer() {
    if (activeTimer) { clearInterval(activeTimer); activeTimer = null; }
    timerElapsed = 0;
}

function pad(n) { return (n < 10 ? '0' : '') + n; }

// ---- UI HELPERS ----
function switchTab(tabName, btn) {
    var tabs = document.querySelectorAll('.tab-content');
    for (var i = 0; i < tabs.length; i++) tabs[i].className = 'tab-content';
    var btns = document.querySelectorAll('.tab-btn');
    for (var j = 0; j < btns.length; j++) btns[j].className = 'tab-btn';
    document.getElementById('tab-' + tabName).className = 'tab-content active';
    btn.className = 'tab-btn active';
}

function closeModal(id) { document.getElementById(id).className = 'modal-overlay'; }

function showToast(msg, type) {
    var toast = document.getElementById('toast');
    toast.innerHTML = escHtml(msg);
    toast.className = 'toast ' + (type || '') + ' show';
    setTimeout(function() { toast.className = 'toast'; }, 2500);
}

function formatRole(role) {
    var map = {
        operator: 'Operator', setup_operator: 'Setup Operator', qc_technician: 'QC Technician',
        programmer: 'Programmer', deburr_operator: 'Deburr Operator', material_handler: 'Material Handler',
        driver: 'Driver', shipping_technician: 'Shipping Tech'
    };
    return map[role] || (role || '').replace(/_/g, ' ');
}

function escHtml(s) {
    if (!s) return '';
    var d = document.createElement('div');
    d.appendChild(document.createTextNode(s));
    return d.innerHTML;
}
